/**
 * slides-as-code-design.js
 *
 * Example deck generated by the /create-deck skill (pptxgenjs engine, default theme).
 * Source outline: outlines/slides-as-code-design.md
 *
 * This file is the source of truth for the deck. Edit it and re-run to regenerate.
 *
 * Usage:
 *   npm install -g pptxgenjs react react-dom react-dom-server react-icons sharp
 *   node slides-as-code-design.js
 *
 * Output: output/slides-as-code-design.pptx
 *
 * Module format: CommonJS (require). Do not rename to .mjs without converting
 * all require() calls to import statements.
 */

const pptxgen = require("pptxgenjs");
const fs = require("fs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");

// ═══════════════════════════════════════════════════════════════
// Theme: Default (clean dark slate)
// ═══════════════════════════════════════════════════════════════
const C = {
  background: "1E293B",
  background_alt: "0F172A",
  surface: "334155",
  text_primary: "F8FAFC",
  text_secondary: "94A3B8",
  text_body: "CBD5E1",
  accent: "3B82F6",
  accent_alt: "10B981",
  warning: "EF4444",
};
const FONTS = { heading: "Trebuchet MS", body: "Calibri", mono: "Consolas" };

// Safe-area constants (LAYOUT_WIDE = 13.33" x 7.5")
const SW = 13.33;
const SH = 7.5;
const M = 0.5;
const CONTENT_W = SW - 2 * M;
const CONTENT_Y = 1.2;
const FOOTER_Y = SH - 0.6;
const CONTENT_H = FOOTER_Y - CONTENT_Y;
const RIGHT_EDGE = SW - M;

const TOTAL = 27;

// Shadow factory — never reuse shadow objects
const cardShadow = () => ({
  type: "outer", blur: 4, offset: 2,
  angle: 135, color: "000000", opacity: 0.12,
});

// ═══════════════════════════════════════════════════════════════
// Icon helpers
// ═══════════════════════════════════════════════════════════════
function renderIconSvg(IconComponent, size = 256, color = "FFFFFF") {
  const el = React.createElement(IconComponent, { size, color: `#${color}` });
  return ReactDOMServer.renderToStaticMarkup(el);
}

async function iconToBase64(svgString, size = 256) {
  const buf = Buffer.from(svgString);
  const png = await sharp(buf, { density: 300 })
    .resize(size, size)
    .png()
    .toBuffer();
  return `image/png;base64,${png.toString("base64")}`;
}

// ═══════════════════════════════════════════════════════════════
// Footer helper
// ═══════════════════════════════════════════════════════════════
function addFooter(slide, slideNum, opts = {}) {
  const { suppressNumber = false } = opts;
  if (!suppressNumber) {
    slide.addText(`${slideNum}`, {
      x: 0.2, y: SH - 0.45, w: 0.5, h: 0.3,
      fontSize: 10, fontFace: FONTS.body,
      color: C.text_secondary,
    });
  }
}

// ═══════════════════════════════════════════════════════════════
// Layout: Title Slide
// ═══════════════════════════════════════════════════════════════
function addTitleSlide(pptx, title, subtitle, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background_alt };

  // Large geometric accent shape (top-right)
  slide.addShape(pptx.ShapeType.rect, {
    x: 8.5, y: -1.0, w: 6.0, h: 6.0,
    fill: { color: C.accent },
    transparency: 90,
    rotate: 15,
  });

  // Another rotated shape (bottom-left)
  slide.addShape(pptx.ShapeType.rect, {
    x: -2.0, y: 4.0, w: 5.0, h: 5.0,
    fill: { color: C.accent_alt },
    transparency: 92,
    rotate: -20,
  });

  // Accent line
  slide.addShape(pptx.ShapeType.rect, {
    x: 1.5, y: 2.6, w: 2.5, h: 0.06,
    fill: { color: C.accent },
  });

  // Title
  slide.addText(title, {
    x: 1.5, y: 2.8, w: 10.0, h: 1.4,
    fontSize: 42, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  // Subtitle
  if (subtitle) {
    slide.addText(subtitle, {
      x: 1.5, y: 4.3, w: 10.0, h: 1.0,
      fontSize: 20, fontFace: FONTS.body,
      color: C.text_secondary,
    });
  }

  // Bottom accent bar
  slide.addShape(pptx.ShapeType.rect, {
    x: 0, y: SH - 0.08, w: SW, h: 0.08,
    fill: { color: C.accent },
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Section Divider (numbered panel)
// ═══════════════════════════════════════════════════════════════
function addSectionDivider(pptx, sectionNumber, title, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  // Left panel
  const panelW = SW * 0.18;
  slide.addShape(pptx.ShapeType.rect, {
    x: 0, y: 0, w: panelW, h: SH,
    fill: { color: C.background_alt },
  });

  // Large faint section number
  const numStr = String(sectionNumber).padStart(2, "0");
  slide.addText(numStr, {
    x: 0, y: SH * 0.3, w: panelW, h: 1.5,
    fontSize: 96, fontFace: FONTS.heading,
    color: C.text_secondary, bold: true,
    align: "center", valign: "middle",
    transparency: 70,
  });

  // Accent vertical bar at panel edge
  slide.addShape(pptx.ShapeType.rect, {
    x: panelW - 0.04, y: 0, w: 0.04, h: SH,
    fill: { color: C.accent },
  });

  // Right side content
  const rightX = panelW + 0.6;
  const rightW = SW - rightX - M;

  slide.addText("SECTION", {
    x: rightX, y: SH * 0.35, w: rightW, h: 0.4,
    fontSize: 12, fontFace: FONTS.body,
    color: C.text_secondary,
    charSpacing: 6,
  });

  slide.addText(title, {
    x: rightX, y: SH * 0.42, w: rightW, h: 1.2,
    fontSize: 42, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  slide.addShape(pptx.ShapeType.rect, {
    x: rightX, y: SH * 0.42 + 1.25, w: 2.0, h: 0.06,
    fill: { color: C.accent },
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Card Grid (2x2, 2x3, or flexible)
// ═══════════════════════════════════════════════════════════════
function addCardGrid(pptx, title, cards, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  const n = cards.length;
  const cols = n <= 4 ? 2 : 3;
  const rows = Math.ceil(n / cols);
  const gap = 0.4;
  const cardW = (CONTENT_W - (cols - 1) * gap) / cols;
  const cardH = (CONTENT_H - (rows - 1) * gap) / rows;

  cards.forEach((card, i) => {
    const col = i % cols;
    const row = Math.floor(i / cols);
    const x = M + col * (cardW + gap);
    const y = CONTENT_Y + row * (cardH + gap);
    const accentColor = [C.accent, C.accent_alt, C.warning, C.accent][i % 4];

    // Card background
    slide.addShape(pptx.ShapeType.rect, {
      x, y, w: cardW, h: cardH,
      fill: { color: C.surface },
      shadow: cardShadow(),
    });

    // Left accent bar
    slide.addShape(pptx.ShapeType.rect, {
      x, y, w: 0.06, h: cardH,
      fill: { color: accentColor },
    });

    // Icon circle (if provided)
    if (card.iconImg) {
      slide.addShape(pptx.ShapeType.ellipse, {
        x: x + 0.25, y: y + 0.25, w: 0.55, h: 0.55,
        fill: { color: C.background },
      });
      slide.addImage({
        data: card.iconImg,
        x: x + 0.33, y: y + 0.33, w: 0.39, h: 0.39,
      });
    }

    // Card title
    const titleX = card.iconImg ? x + 0.95 : x + 0.25;
    const titleW = card.iconImg ? cardW - 1.1 : cardW - 0.45;
    slide.addText(card.title, {
      x: titleX, y: y + 0.2, w: titleW, h: 0.55,
      fontSize: 18, fontFace: FONTS.heading,
      color: C.text_primary, bold: true,
      valign: "middle",
    });

    // Card body
    slide.addText(card.body, {
      x: x + 0.25, y: y + 0.85, w: cardW - 0.45, h: cardH - 1.1,
      fontSize: 14, fontFace: FONTS.body,
      color: C.text_body, valign: "top",
    });
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Icon + Text Rows
// ═══════════════════════════════════════════════════════════════
function addIconRows(pptx, title, items, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  const rowH = CONTENT_H / items.length;

  items.forEach((item, i) => {
    const y = CONTENT_Y + i * rowH;
    const circleSize = 0.65;
    const circleY = y + rowH / 2 - circleSize / 2;

    if (item.iconImg) {
      slide.addShape(pptx.ShapeType.ellipse, {
        x: M + 0.3, y: circleY, w: circleSize, h: circleSize,
        fill: { color: C.surface },
      });
      slide.addImage({
        data: item.iconImg,
        x: M + 0.38, y: circleY + 0.08, w: 0.49, h: 0.49,
      });
    } else {
      // Accent bar fallback
      slide.addShape(pptx.ShapeType.rect, {
        x: M + 0.56, y: circleY, w: 0.06, h: circleSize,
        fill: { color: item.accentColor || C.accent },
      });
    }

    slide.addText(item.label, {
      x: M + 1.3, y: y + rowH * 0.12, w: CONTENT_W - 1.5, h: 0.4,
      fontSize: 20, fontFace: FONTS.heading,
      color: C.text_primary, bold: true,
    });

    slide.addText(item.description, {
      x: M + 1.3, y: y + rowH * 0.12 + 0.4, w: CONTENT_W - 1.5,
      h: rowH * 0.55,
      fontSize: 14, fontFace: FONTS.body,
      color: C.text_body,
    });

    // Separator
    if (i < items.length - 1) {
      slide.addShape(pptx.ShapeType.rect, {
        x: M + 1.3, y: y + rowH - 0.01, w: CONTENT_W - 1.5, h: 0.01,
        fill: { color: C.surface },
      });
    }
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Process Flow
// ═══════════════════════════════════════════════════════════════
function addStepBox(slide, pptx, step, index, x, y, w, h) {
  slide.addShape(pptx.ShapeType.rect, {
    x, y, w, h,
    fill: { color: C.surface },
    shadow: cardShadow(),
  });

  // Step number circle
  const circleSize = 0.45;
  slide.addShape(pptx.ShapeType.ellipse, {
    x: x + (w - circleSize) / 2, y: y + 0.15, w: circleSize, h: circleSize,
    fill: { color: C.accent },
  });
  slide.addText(`${index + 1}`, {
    x: x + (w - circleSize) / 2, y: y + 0.15, w: circleSize, h: circleSize,
    fontSize: 18, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
    align: "center", valign: "middle",
  });

  // Split step text on first \n
  const nlIndex = step.indexOf("\n");
  if (nlIndex > -1) {
    const label = step.substring(0, nlIndex);
    const desc = step.substring(nlIndex + 1);

    slide.addText(label, {
      x: x + 0.1, y: y + 0.7, w: w - 0.2, h: 0.45,
      fontSize: 14, fontFace: FONTS.heading,
      color: C.text_primary, bold: true,
      align: "center", valign: "top",
    });

    slide.addText(desc, {
      x: x + 0.1, y: y + 1.15, w: w - 0.2, h: h - 1.35,
      fontSize: 12, fontFace: FONTS.body,
      color: C.text_body, align: "center", valign: "top",
    });
  } else {
    slide.addText(step, {
      x: x + 0.1, y: y + 0.7, w: w - 0.2, h: h - 0.9,
      fontSize: 13, fontFace: FONTS.body,
      color: C.text_body, align: "center", valign: "top",
    });
  }
}

function addProcessFlow(pptx, title, steps, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  const n = steps.length;

  if (n <= 4) {
    const gap = n <= 3 ? 0.6 : 0.4;
    const totalGap = (n - 1) * gap;
    const stepW = Math.min(2.8, (CONTENT_W - totalGap) / n);
    const totalW = n * stepW + totalGap;
    const startX = (SW - totalW) / 2;
    const boxH = 2.8;
    const boxY = CONTENT_Y + (CONTENT_H - boxH) / 2;

    steps.forEach((step, i) => {
      const x = startX + i * (stepW + gap);
      addStepBox(slide, pptx, step, i, x, boxY, stepW, boxH);

      if (i < n - 1) {
        slide.addText("\u2192", {
          x: x + stepW, y: boxY + boxH / 2 - 0.5, w: gap, h: 1.0,
          fontSize: 28, color: C.accent,
          align: "center", valign: "middle",
        });
      }
    });
  } else {
    const topCount = Math.ceil(n / 2);
    const botCount = n - topCount;
    const gap = 0.35;
    const stepW = Math.min(2.4, (CONTENT_W - (topCount - 1) * gap) / topCount);
    const boxH = 2.1;
    const rowGap = 0.4;
    const totalH = 2 * boxH + rowGap;
    const startY = CONTENT_Y + (CONTENT_H - totalH) / 2;

    // Top row
    const topW = topCount * stepW + (topCount - 1) * gap;
    const topStartX = (SW - topW) / 2;
    for (let i = 0; i < topCount; i++) {
      const x = topStartX + i * (stepW + gap);
      addStepBox(slide, pptx, steps[i], i, x, startY, stepW, boxH);
      if (i < topCount - 1) {
        slide.addText("\u2192", {
          x: x + stepW, y: startY + boxH / 2 - 0.4, w: gap, h: 0.8,
          fontSize: 24, color: C.accent, align: "center", valign: "middle",
        });
      }
    }

    // Connecting arrow from top-right to bottom-left
    const topLastX = topStartX + (topCount - 1) * (stepW + gap) + stepW;
    const botW = botCount * stepW + (botCount - 1) * gap;
    const botStartX = (SW - botW) / 2;
    const botY = startY + boxH + rowGap;

    slide.addText("\u21B5", {
      x: (topLastX + botStartX) / 2 - 0.3, y: startY + boxH, w: 0.6, h: rowGap,
      fontSize: 24, color: C.accent, align: "center", valign: "middle",
    });

    for (let i = 0; i < botCount; i++) {
      const x = botStartX + i * (stepW + gap);
      addStepBox(slide, pptx, steps[topCount + i], topCount + i, x, botY, stepW, boxH);
      if (i < botCount - 1) {
        slide.addText("\u2192", {
          x: x + stepW, y: botY + boxH / 2 - 0.4, w: gap, h: 0.8,
          fontSize: 24, color: C.accent, align: "center", valign: "middle",
        });
      }
    }
  }

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Two-Column
// ═══════════════════════════════════════════════════════════════
function addTwoColumn(pptx, title, leftHeader, rightHeader, leftContent, rightContent, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  const col1W = 5.70;
  const gutter = 0.36;
  const col2X = M + col1W + gutter;
  const col2W = CONTENT_W - col1W - gutter;
  const headerY = CONTENT_Y;
  const bodyY = CONTENT_Y + 0.55;
  const bodyH = CONTENT_H - 0.55;

  // Column headers
  if (leftHeader) {
    slide.addText(leftHeader, {
      x: M, y: headerY, w: col1W, h: 0.45,
      fontSize: 20, fontFace: FONTS.heading,
      color: C.accent, bold: true,
    });
  }
  if (rightHeader) {
    slide.addText(rightHeader, {
      x: col2X, y: headerY, w: col2W, h: 0.45,
      fontSize: 20, fontFace: FONTS.heading,
      color: C.accent, bold: true,
    });
  }

  // Vertical divider
  slide.addShape(pptx.ShapeType.rect, {
    x: M + col1W + gutter / 2 - 0.01, y: CONTENT_Y,
    w: 0.02, h: CONTENT_H,
    fill: { color: C.surface },
  });

  // Left column
  slide.addText(leftContent.map(item => ({
    text: item,
    options: {
      fontSize: 16, fontFace: FONTS.body,
      color: C.text_body, bullet: true,
      breakLine: true, paraSpaceAfter: 10,
    },
  })), {
    x: M, y: bodyY, w: col1W, h: bodyH,
    valign: "top",
  });

  // Right column
  slide.addText(rightContent.map(item => ({
    text: item,
    options: {
      fontSize: 16, fontFace: FONTS.body,
      color: C.text_body, bullet: true,
      breakLine: true, paraSpaceAfter: 10,
    },
  })), {
    x: col2X, y: bodyY, w: col2W, h: bodyH,
    valign: "top",
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Code Block Slide
// ═══════════════════════════════════════════════════════════════
function addCodeSlide(pptx, title, code, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  // Code panel background
  slide.addShape(pptx.ShapeType.rect, {
    x: M, y: CONTENT_Y, w: CONTENT_W, h: CONTENT_H,
    fill: { color: "0D1117" },
  });

  // Accent top bar on panel
  slide.addShape(pptx.ShapeType.rect, {
    x: M, y: CONTENT_Y, w: CONTENT_W, h: 0.05,
    fill: { color: C.accent },
  });

  // Code text
  slide.addText(code, {
    x: M + 0.3, y: CONTENT_Y + 0.25, w: CONTENT_W - 0.6, h: CONTENT_H - 0.4,
    fontSize: 14, fontFace: FONTS.mono,
    color: "58A6FF",
    valign: "top",
    paraSpaceAfter: 6,
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Bullet Slide
// ═══════════════════════════════════════════════════════════════
function addBulletSlide(pptx, title, bullets, slideNum, notes) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  let bodySize, leadSize, spacing;
  if (bullets.length <= 4) {
    bodySize = 22; leadSize = 24; spacing = 20;
  } else if (bullets.length <= 5) {
    bodySize = 20; leadSize = 22; spacing = 16;
  } else {
    bodySize = 18; leadSize = 20; spacing = 12;
  }

  const textItems = [];
  bullets.forEach(b => {
    // Check for bold lead-in pattern
    const match = b.match(/^\*\*(.+?)\*\*\s*[—:]\s*(.*)/);
    if (match) {
      textItems.push(
        { text: `${match[1]}: `, options: { bold: true, fontSize: leadSize, color: C.text_primary } },
        { text: match[2], options: { fontSize: bodySize, color: C.text_body, breakLine: true } },
      );
    } else {
      textItems.push({ text: b, options: { fontSize: bodySize, color: C.text_body, bullet: true, breakLine: true } });
    }
  });

  slide.addText(textItems, {
    x: M + 0.4, y: CONTENT_Y, w: CONTENT_W - 0.8, h: CONTENT_H,
    valign: "top",
    paraSpaceAfter: spacing,
    fontFace: FONTS.body,
  });

  if (notes) {
    slide.addNotes(notes);
  }

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Closing Slide
// ═══════════════════════════════════════════════════════════════
function addClosingSlide(pptx, title, bullets, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background_alt };

  // Decorative accent shapes
  slide.addShape(pptx.ShapeType.rect, {
    x: -1.0, y: -2.0, w: 5.0, h: 5.0,
    fill: { color: C.accent },
    transparency: 92,
    rotate: 25,
  });
  slide.addShape(pptx.ShapeType.rect, {
    x: 11.5, y: 5.8, w: 3.5, h: 3.5,
    fill: { color: C.accent_alt },
    transparency: 92,
    rotate: -15,
  });

  // Top accent bar
  slide.addShape(pptx.ShapeType.rect, {
    x: 0, y: 0, w: SW, h: 0.06,
    fill: { color: C.accent },
  });

  // Title
  slide.addText(title, {
    x: M, y: 1.5, w: CONTENT_W, h: 1.0,
    fontSize: 36, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
    align: "center",
  });

  // Accent line below title
  slide.addShape(pptx.ShapeType.rect, {
    x: SW / 2 - 1.25, y: 2.6, w: 2.5, h: 0.06,
    fill: { color: C.accent },
  });

  // Bullet points
  if (bullets && bullets.length > 0) {
    slide.addText(bullets.map(b => ({
      text: `\u2022  ${b}`,
      options: {
        fontSize: 18, fontFace: FONTS.body,
        color: C.text_secondary,
        breakLine: true, paraSpaceAfter: 14,
      },
    })), {
      x: 2.0, y: 3.0, w: SW - 4.0, h: 3.5,
      valign: "top",
      align: "left",
    });
  }

  // Bottom accent bar
  slide.addShape(pptx.ShapeType.rect, {
    x: 0, y: SH - 0.06, w: SW, h: 0.06,
    fill: { color: C.accent },
  });

  addFooter(slide, slideNum, { suppressNumber: true });
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Two-Column with Logo Headers
// ═══════════════════════════════════════════════════════════════
function addTwoColumnWithLogos(pptx, title, leftHeader, rightHeader, leftContent, rightContent, leftIcon, rightIcon, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  const col1W = 5.70;
  const gutter = 0.36;
  const col2X = M + col1W + gutter;
  const col2W = CONTENT_W - col1W - gutter;
  const headerH = 0.52;

  // Header backgrounds with accent bars
  function addColumnHeader(x, w, header, iconData) {
    slide.addShape(pptx.ShapeType.rect, {
      x, y: CONTENT_Y, w, h: headerH,
      fill: { color: C.surface },
    });
    slide.addShape(pptx.ShapeType.rect, {
      x, y: CONTENT_Y, w, h: 0.05,
      fill: { color: C.accent },
    });

    if (iconData) {
      slide.addImage({
        data: iconData,
        x: x + 0.12, y: CONTENT_Y + 0.1, w: 0.32, h: 0.32,
      });
    }
    const textX = iconData ? x + 0.55 : x + 0.15;
    slide.addText(header, {
      x: textX, y: CONTENT_Y + 0.02, w: w - (textX - x) - 0.1, h: headerH - 0.04,
      fontSize: 18, fontFace: FONTS.heading,
      color: C.text_primary, bold: true, valign: "middle",
    });
  }

  if (leftHeader) addColumnHeader(M, col1W, leftHeader, leftIcon);
  if (rightHeader) addColumnHeader(col2X, col2W, rightHeader, rightIcon);

  // Vertical divider
  slide.addShape(pptx.ShapeType.rect, {
    x: M + col1W + gutter / 2 - 0.01, y: CONTENT_Y,
    w: 0.02, h: CONTENT_H,
    fill: { color: C.surface },
  });

  const bodyY = CONTENT_Y + headerH + 0.15;
  const bodyH = CONTENT_H - headerH - 0.15;

  slide.addText(leftContent.map(item => ({
    text: item,
    options: {
      fontSize: 16, fontFace: FONTS.body,
      color: C.text_body, bullet: true,
      breakLine: true, paraSpaceAfter: 10,
    },
  })), {
    x: M, y: bodyY, w: col1W, h: bodyH, valign: "top",
  });

  slide.addText(rightContent.map(item => ({
    text: item,
    options: {
      fontSize: 16, fontFace: FONTS.body,
      color: C.text_body, bullet: true,
      breakLine: true, paraSpaceAfter: 10,
    },
  })), {
    x: col2X, y: bodyY, w: col2W, h: bodyH, valign: "top",
  });

  addFooter(slide, slideNum);
  return slide;
}

// ═══════════════════════════════════════════════════════════════
// Layout: Three-Column Cards
// ═══════════════════════════════════════════════════════════════
function addThreeColumnCards(pptx, title, cards, slideNum) {
  const slide = pptx.addSlide();
  slide.background = { color: C.background };

  slide.addText(title, {
    x: M, y: 0.3, w: CONTENT_W, h: 0.7,
    fontSize: 28, fontFace: FONTS.heading,
    color: C.text_primary, bold: true,
  });

  const cardW = 3.5, cardH = CONTENT_H;
  const gap = 0.5;
  const totalW = 3 * cardW + 2 * gap;
  const startX = (SW - totalW) / 2;

  cards.slice(0, 3).forEach((card, i) => {
    const x = startX + i * (cardW + gap);
    const accentColor = [C.accent, C.accent_alt, C.warning][i];

    slide.addShape(pptx.ShapeType.rect, {
      x, y: CONTENT_Y, w: cardW, h: cardH,
      fill: { color: C.surface },
      shadow: cardShadow(),
    });

    slide.addShape(pptx.ShapeType.rect, {
      x, y: CONTENT_Y, w: cardW, h: 0.06,
      fill: { color: accentColor },
    });

    if (card.iconImg) {
      slide.addShape(pptx.ShapeType.ellipse, {
        x: x + (cardW - 0.6) / 2, y: CONTENT_Y + 0.25, w: 0.6, h: 0.6,
        fill: { color: C.background },
      });
      slide.addImage({
        data: card.iconImg,
        x: x + (cardW - 0.42) / 2, y: CONTENT_Y + 0.34, w: 0.42, h: 0.42,
      });
    }

    const headingY = card.iconImg ? CONTENT_Y + 1.0 : CONTENT_Y + 0.25;
    slide.addText(card.heading, {
      x: x + 0.2, y: headingY, w: cardW - 0.4, h: 0.6,
      fontSize: 18, fontFace: FONTS.heading,
      color: C.text_primary, bold: true,
      align: "center",
    });

    slide.addText(card.content, {
      x: x + 0.2, y: headingY + 0.65, w: cardW - 0.4, h: cardH - (headingY - CONTENT_Y) - 0.9,
      fontSize: 13, fontFace: FONTS.body,
      color: C.text_body, valign: "top",
      align: "center",
    });
  });

  addFooter(slide, slideNum);
  return slide;
}

